INSERT INTO `documents_document` (`id`, `title`, `title_key`, `file`, `file_path`, `source_url`, `crop`, `content_type`, `doc_type`, `geography`, `year`, `source`, `summary`, `authors`, `organizations`, `journal_or_book`, `countries`, `status`, `uploaded_at`, `updated_at`, `published_on`, `review_notes`, `category_id`, `reviewed_by_id`, `uploaded_by_id`, `subcategory_id`) VALUES
(1, 'Benefits of Azolla in Rice', 'benefits-of-azolla-in-rice', 'documents/Azolla_English-8-x-11-in.pdf', 'Azolla_English-8-x-11-in.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Information on benefits of Azolla application in rice, how much to apply, how to apply, two methods to use Azolla in rice, one method using shallow water bed and other in standing water', '', 'IRRI', 'IRRI documents', 'India', 'Published', '2026-04-24 02:36:56.207491', '2026-04-24 12:09:39.356023', NULL, '', 1, NULL, 1, 1),
(2, 'Crop nutrient management using Nutrient Expert improves yield, increases farmers’ income and reduces greenhouse gas emissions', 'crop-nutrient-management-using-nutrient-expert-improves-yield-increases-farmers-income-and-reduces-greenhouse-gas-emissions', 'documents/Crop_nutrient_management.pdf', '', 'https://www.nature.com/articles/s41598-020-79883-x', 'Rice', 'Research Paper', 'Research Article', 'India (Punjab, Haryana, Bihar); Mexico; Philippines; Colombia; Morocco', 2021, 'CIMMYT, IRRI,ICAR,CGIAR, IPNI and APNI', 'This study evaluated Nutrient Expert-based site-specific nutrient management in rice and wheat across the Indo-Gangetic Plains of India. Results showed reduced nitrogen use (15–35%), increased grain yield (4–8%), higher farmer income, and lower greenhouse gas emissions (2–20%) compared to farmers’ practices. The findings highlight the potential of decision-support tools to improve nutrient use efficiency and promote climate-smart agriculture.', 'Tek B. Sapkota', 'CIMMYT, IRRI,ICAR,CGIAR, IPNI and APNI', 'Scientific Reports', 'India (Punjab, Haryana, Bihar); Mexico; Philippines; Colombia; Morocco', 'Published', '2026-04-24 02:36:56.258500', '2026-04-24 12:09:39.255013', NULL, '', 2, NULL, 1, 2),
(3, 'Benefits of Vermicompost in Rice', 'benefits-of-vermicompost-in-rice', 'documents/Vermicompost_English-8-x-11-in.pdf', 'Vermicompost_English-8-x-11-in.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Information on benefits of vermicomposting, methods of preparation of vermicompost, amount of earthworrm required', '', 'IRRI', 'IRRI documents', 'India', 'Published', '2026-04-24 02:36:56.391815', '2026-04-24 12:09:39.165015', NULL, '', 1, NULL, 1, 3),
(4, 'Trichoderma', 'trichoderma', 'documents/Trichoderma_English-8-x-11-in.pdf', 'Trichoderma_English-8-x-11-in.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'All India', NULL, 'IRRI', '', '', 'IRRI', '', '', 'Published', '2026-04-24 02:36:56.504327', '2026-04-24 12:09:39.104017', NULL, '', 1, NULL, 1, 4),
(5, 'Package and Practices forDirect Seeded Rice – A Technology for Enhancing Climate Resilience and Farm Profitability', 'package-and-practices-fordirect-seeded-rice-a-technology-for-enhancing-climate-resilience-and-farm-profitability', 'documents/CRRI_Technology-Bulletin_No-250.pdf', 'CRRI_Technology-Bulletin_No-250.pdf', '', 'Rice', 'Advisory', 'Bulletin', 'India', 2025, 'NRRI', 'Select heavy, well-levelled fields; avoid sandy/light soils for DSR.Sow 7–10 days before monsoon at 2–3 cm depth using a seed drill for uniform spacing.Use recommended seed rate (20–25 kg/ha) to avoid lodging and pest problems.Treat seeds before sowing with Carbendazim/Trichoderma to prevent seed-borne diseases.Apply full P & K as basal dose and split nitrogen in 3 stages (14 DAS, tillering, panicle initiation).Monitor nitrogen need using Leaf Colour Chart (LCC) to avoid excess urea use.Control weeds early (15–40 DAS critical period) using pre- and post-emergence herbicides or mechanical weeding.Avoid continuous standing water; follow alternate wetting and drying irrigation.Maintain thin water layer (about 5 cm) at flowering stage to prevent yield loss.Ensure proper drainage and timely operations to reduce costs and increase profitability under DSR.', 'Anjani Kumar, Sangita Mohanty, Abhishek Kumar Sahu, R P Sah and Arvind Yadav', 'NRRI', 'NRRI bulletin', 'India', 'Published', '2026-04-24 02:36:56.592316', '2026-04-24 12:09:39.074467', NULL, '', 3, NULL, 1, 5),
(6, 'Dhaincha', 'dhaincha', 'documents/Improved_package_of_practice_for_Dhaincha_Seed.pdf', 'Dhaincha', '', 'Rice', 'Advisory', 'Factsheet', 'India', 2024, 'IRRI', 'Information on benefits of Dhaincha, how to apply Dhaincha in rice', '', 'IRRI', 'IRRI documents', 'India', 'Published', '2026-04-24 02:36:56.639252', '2026-04-24 12:09:39.023469', NULL, '', 1, NULL, 1, 6),
(7, 'Rice Production Manual – Nutrient Management', 'rice-production-manual-nutrient-management', 'documents/IRRI_Rice_Production_Manual_for_Odisha_Nutrient_Management.pdf', '', '', 'Rice', 'Advisory', 'Training Manual', 'India', NULL, 'IRRI', 'The essential nutrients and their functions and deficiency symptoms in rice production-An introduction of the principles of site-specific nutrient management (SSNM) and the steps in determining fertilizer requirements-Explain the guidelines and procedures for using the leaf colour chart (LCC) to determine the N status of leaves in a standing crop', 'IRRI', 'IRRI', 'IRRI Rice Production Manual', 'India', 'Published', '2026-04-24 02:36:56.701692', '2026-04-24 12:09:38.997432', NULL, '', NULL, NULL, 1, NULL),
(8, 'Zinc deficiency', 'zinc-deficiency', 'documents/zinc-deficiency-english.pdf', 'zinc-deficiency-english.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Zinc application enhances grain filling and weight of rice grains. Zinc deficiency symptom: Zinc deficiency in rice shows up 2-4 weeks after planting young plants. Look for dusty brown spots on the top leaves of weak, stunted plants. You\'ll see uneven growth such as some areas with thin, poorly rooted hills that might bounce back on their own. Plants stop making new tillers, take longer to mature, and have more empty grains if it\'s bad. Younger leaves get yellow stripes near the base, lose stiffness, turn brown with big blotches and streaks on bottom leaves, sometimes a white line down the middle, and leaves stay small overall.Zinc deficiency management: Grow Zn-efficient varieties. Contact your local agriculture office for an up-to-date list of available varieties. Per acre Apply 10 kg zinc sulphate, at least once in a year. Apply organic manure before seeding or transplanting or applied to the nursery seedbed a few days before transplanting. Allow permanently flooded fields to drain and dry out periodically. Monitor irrigation water quality.', 'IRRI-RKBO', 'IRRI', 'Zinc deficiency-RKB', 'India', 'Published', '2026-04-24 02:36:56.725018', '2026-04-24 12:09:38.828868', NULL, '', 4, NULL, 1, 7),
(9, 'Split application of nitrogen', 'split-application-of-nitrogen', 'documents/nitrogen-split-applications-english.pdf', 'nitrogen-split-applications-english', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Split application of Nitrogen: The splitting pattern approach provides a recommendation for the total N fertilizer requirement (kg/ha) and a plan for the splitting and timing of applications in accordance with crop growth stage, cropping season, variety used, and crop establishment method. Nitrogen split applications improve rice fertilizer efficiency for farmers, especially when frequent field checks aren\'t possible. Use the splitting pattern based on rice variety duration, growth stages, and Leaf Color Chart (LCC) adjustments from the provided fact sheet.Key Application Steps•	Estimate total N need: Set up a no-fertilizer (-F) plot to find N-limited yield, then target 60-120 kg N/ha based on attainable yield and variety; common split for transplanting is 30-30-0 for 60 kg N total.•	Follow stage-wise splits: For 80-100 day varieties: 30 kg basal, 15 kg tillering, 15 kg panicle initiation (total 60 kg); adjust up for longer varieties like 40-20-20 for 80 kg or 60-20-20-20 for 120 kg.•	Adjust with LCC: At each stage, check leaves—if below critical LCC value, apply 33% more N; if equal, standard dose; if above, postpone and reduce by 33% to match crop demand', 'IRRI-RKBO', 'IRRI', 'Split application of Nitrogen-RKB', 'India', 'Published', '2026-04-24 02:36:56.774042', '2026-04-24 12:09:38.775884', NULL, '', 5, NULL, 1, 8),
(10, 'Nitrogen deficiency in rice', 'nitrogen-deficiency-in-rice', 'documents/nitrogen-deficiency-english.pdf', '', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Nitrogen (N) deficiency is one of the most common problems in rice in Asia. It is common in all rice-growing soils where modern varieties are grown without sufficient mineral N fertilizer. Nitrogen deficiency symptoms :  Nitrogen deficiency makes rice plants weak and small, with fewer tillers and low yield. Older leaves turn lemon-yellowish green, narrow, short, and upright—tips go light green or yellow. Whole field looks pale yellow; under bad stress, leaves die. Young leaves stay greener; fewer panicles mean empty grains. Don\'t mix up with sulfur (hits young leaves first) or iron lack (starts on new leaf). Nitrogen deficiency management: To manage nitrogen deficiency in rice, apply fertilizer smartly in splits: give one-third basal at planting, another third at tillering (20-25 days after transplanting), and the last at panicle initiation (40-50 days), using urea or ammonium sulfate based on soil tests—about 100-120 kg N per hectare total for good yields. Keep fields flooded to hold nitrogen but drain briefly after applying to avoid runoff losses; use quality seeds of high-yielding varieties at right spacing (20x15 cm) to help plants take up N better, and control weeds early since they steal nitrogen. Hybrids need less N than traditional types, so adjust amounts—test soil and plants if unsure to avoid waste.', 'IRRI-RKBO', 'IRRI', 'Nitrogen deficiency management-RKBO', 'India', 'Published', '2026-04-24 02:36:56.855384', '2026-04-24 12:09:38.756870', NULL, '', 6, NULL, 1, 9),
(11, 'Phosphorus deificiency in rice', 'phosphorus-deificiency-in-rice', 'documents/Phosphorus_P_-_IRRI_Rice_Knowledge_Bank.pdf', 'Phosphorus (P) - IRRI Rice Knowledge Bank.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Phosphorous deficiency symptoms. Stunted dark green plants with erect leaves and reduced tillering; thin and spindly stems; delayed maturity (and no flowering at all with severe P deficiency); and high levels of unfilled grainsPhosphorus is often deficient in sandy, soils with low organic matter content; calcareous/saline/alkaline soils; degraded lowland soils; volcanic ash soils or acid upland soils with high phosphorus fixation capacity; peat soils; and, acid sulfate soils high in active iron and aluminum.Phosphorus dose for rice: Per one acre 15 kg phosphorus is required to be applied at basal dose.Timing of application of Phosphorus fertilizer: Incorporate all fertilizer Phosphorus before the last soil puddling before transplanting or topdress all P within 10?15 days after direct seeding.', 'IRRI-RKBO', 'IRRI', 'Phosphorus deficiency management-RKBO', 'India', 'Published', '2026-04-24 02:36:56.907640', '2026-04-24 12:09:38.662869', NULL, '', 4, NULL, 1, 10),
(12, 'Trichoderma seed treatment in rice', 'trichoderma-seed-treatment-in-rice', 'documents/Trichoderma_English-8-x-11-in.pdf', 'Trichoderma_English-8-x-11-in.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Trichoderma seed treatment in rice: Seed Treatment: Mix 10 grams of Trichoderma powder with 1 kg of pre-germinated paddy seeds, then dry in the shade for 1 hour before sowing.Rice Root Dipping: Prepare a solution by mixing 10 grams of Trichoderma powder in 1 litre of water and dip seedling roots for 10-15 minutes before transplanting.', 'IRRI-RKBO', 'IRRI', 'Trichoderma application in rice-RKBO', 'India', 'Published', '2026-04-24 02:36:56.990681', '2026-04-24 12:09:38.197642', NULL, '', 7, NULL, 1, 11),
(13, 'Phospohorus (P)', 'phospohorus-p', '', '', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Role of Phosphorus in rice, how to manage Phosphorus, sources of Phosphorus', 'IRRI-RKBO', 'IRRI', 'Phosporus', 'India', 'Published', '2026-04-24 02:36:57.037558', '2026-04-24 02:36:57.037558', NULL, '', 8, NULL, 1, 12),
(14, 'Nitrogen (N)', 'nitrogen-n', 'documents/Nitrogen_N_-_IRRI_Rice_Knowledge_Bank.pdf', 'Nitrogen', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Role of Nitrogen in rice, how to manage Nitrogen, sources of Nitrogen', 'IRRI-RKBO', 'IRRI', 'Nitrogen', 'India', 'Published', '2026-04-24 02:36:57.091728', '2026-04-24 12:09:38.056644', NULL, '', 8, NULL, 1, 12),
(15, 'Fe (Iron) toxicity', 'fe-iron-toxicity', 'documents/iron-toxicity-english.pdf', 'iron-toxicity-english.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Iron (Fe) toxicity causes leaf bronzing and reduced root oxidation power.Symptoms of Iron toxicity are: Tiny brown spots on lower leaves starting from tip and spread toward the leaf base or whole leaf coloured orange-yellow to brown. Spots combine on leaf intervein and leaves turn orange-brown and die. Leaves narrow but often remain green. In some varieties, leaf tips become orange-yellow and dry up. Leaves appear purple-brown if Fe toxicity is severe. Stunted growth, extremely limited tillering. Coarse, sparse, damaged root system with a dark brown to black coating on the root surface and many dead roots. Freshly uprooted rice hills often have poor root systems with many black roots.Management of bronzing or iron toxicity: Use intermittent irrigation and avoid continuous flooding on poorly drained soils containing a large concentration of Fe and organic matter. Plant Fe tolerant varieties. Balance the use of fertilizers (NPK or NPK+ lime. Apply sufficient Potassium (K) fertilizer. Apply lime on acid soils, do not apply excessive amounts of organic matter (manure, straw) on soils containing large amounts of Fe and organic matter and where drainage is poor. Use urea (less acidifying) instead of ammonium sulfate (more acidifying)', 'IRRI-RKBO', 'IRRI', 'Iron', 'India', 'Published', '2026-04-24 02:36:57.170977', '2026-04-24 12:09:37.609644', NULL, '', 9, NULL, 1, 13),
(16, 'Nutrient management in Direct seeded rice', 'nutrient-management-in-direct-seeded-rice', 'documents/English-DSR-1.pdf', 'English-DSR-1.pdf', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Apply DAP 35 kg/acre, MOP 15–20 kg/acre, and ZnSO? 10 kg/acre at sowing. At 15–25 DAS (with first irrigation or light rain), apply Urea 20 kg/acre for medium and long duration varieties. At the active tillering stage, apply Urea 30–35 kg/acre, and at panicle initiation, apply Urea 30–35 kg/acre along with MOP 15–20 kg/acre. If zinc or iron deficiency appears, spray 1% urea + 0.5% ZnSO? or 0.5% ferrous sulphate 2–3 times at weekly intervals.', 'IRRI-CSISA', 'IRRI', 'Direct seeded rice: A resource conservation technology', 'India', 'Published', '2026-04-24 02:36:57.233527', '2026-04-24 12:09:37.510655', NULL, '', 10, NULL, 1, 14),
(17, 'Potassium (K)', 'potassium-k', 'documents/Potassium_K_-_IRRI_Rice_Knowledge_Bank.pdf', 'Potassium', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Role of potassium, how to manage Potassium, sources of Potassium', 'IRRI-RKBO', 'IRRI', 'Potassium', 'India', 'Published', '2026-04-24 02:36:57.320124', '2026-04-24 12:09:37.363635', NULL, '', 8, NULL, 1, 12),
(18, 'Zinc(Zn)', 'zinczn', 'documents/Zinc_Zn_-_IRRI_Rice_Knowledge_Bank.pdf', '', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'Role of Zinc, how to manage Zinc, zinc deficiency, sources of Zinc', 'IRRI-RKBO', 'IRRI', 'Zinc', 'India', 'Published', '2026-04-24 02:36:57.377654', '2026-04-24 12:09:37.230640', NULL, '', 8, NULL, 1, 12),
(19, 'Leaf Colour Chart (LCC)', 'leaf-colour-chart-lcc', 'documents/Leaf_Color_Chart_-_IRRI_Rice_Knowledge_Bank.pdf', 'Leaf Colour Chart (LCC)', '', 'Rice', 'Advisory', 'Factsheet', 'India', NULL, 'IRRI', 'LCC, how to use LCC, steps to use LCC', 'IRRI-RKBO', 'IRRI', 'Leaf Colour Chart', 'India', 'Published', '2026-04-24 02:36:57.487058', '2026-04-24 12:09:36.755643', NULL, '', 8, NULL, 1, 15),
