(51, '2026-04-24 08:47:16.232941', '', 'Bargarh', '', 'Disease', 'Management Advice', 'Blast disease', '', '', 'variety, land type', 'How can I manage blast disease in my rice crop this season?', 'English', '', 'How can I manage blast disease in my rice crop this season?', 'I\'m sorry, but the context provided does not contain information on managing blast disease in rice. Please provide details about your current practices, any symptoms you\'ve observed, or specific concerns you have regarding the disease.', 'I\'m sorry, but the context provided does not contain information on managing blast disease in rice. Please provide details about your current practices, any symptoms you\'ve observed, or specific concerns you have regarding the disease.', '', 9.97, '', '{\"steps\": [{\"stage\": \"translate_in\", \"ms\": 0}, {\"stage\": \"classify\", \"ms\": 4531}, {\"stage\": \"retrieve\", \"ms\": 4297, \"hits\": 6}, {\"stage\": \"generate\", \"ms\": 1093}, {\"stage\": \"translate_out\", \"ms\": 0}]}', 'Responded', 0, '', NULL, NULL, NULL),
(52, '2026-04-24 10:54:05.162216', '', '', '', 'Fertiliser', 'Management Advice', 'Azolla application', '', '', 'variety, land type', 'How do I apply Azolla in my rice field?', 'English', '', 'How do I apply Azolla in my rice field?', 'To apply Azolla in your rice field, you can use one of two methods:\n\n1. **Shallow Water Bed Method**: \n   - Prepare a shallow water bed in your rice field.\n   - Introduce Azolla into the water bed. \n   - Ensure that the water level is maintained to keep the Azolla floating and growing.\n\n2. **Standing Water Method**: \n   - If your field has standing water, you can directly introduce Azolla into the water.\n   - Allow it to grow and cover the water surface.\n\nMake sure to monitor the growth of Azolla and maintain the water level as needed. The specific dosage for Azolla application is not provided in the context, so you may need to consult local agricultural resources for the recommended amount based on your field size.', 'To apply Azolla in your rice field, you can use one of two methods:\n\n1. **Shallow Water Bed Method**: \n   - Prepare a shallow water bed in your rice field.\n   - Introduce Azolla into the water bed. \n   - Ensure that the water level is maintained to keep the Azolla floating and growing.\n\n2. **Standing Water Method**: \n   - If your field has standing water, you can directly introduce Azolla into the water.\n   - Allow it to grow and cover the water surface.\n\nMake sure to monitor the growth of Azolla and maintain the water level as needed. The specific dosage for Azolla application is not provided in the context, so you may need to consult local agricultural resources for the recommended amount based on your field size.', '', 10.81, '', '{\"steps\": [{\"stage\": \"translate_in\", \"ms\": 0}, {\"stage\": \"classify\", \"ms\": 3921}, {\"stage\": \"retrieve\", \"ms\": 3828, \"hits\": 6}, {\"stage\": \"generate\", \"ms\": 3031}, {\"stage\": \"translate_out\", \"ms\": 0}]}', 'Responded', 0, '', 4, NULL, NUL